      ]
    },
    "selfCheckQuestions": [
      "What is 2/вҲҡ5 in rationalized form?",
      "Why do we multiply both numerator and denominator?"
    ],
    "quickSummary": [
      "Rationalizing makes fractions easier to handle by removing roots from the bottom."
    ],
    "keyTerms": [
      "Surds",
      "Denominator",
      "Conjugate"
    ],
    "fillInTheBlanks": [
      {
        "prompt": "To rationalize 1/вҲҡ7, we multiply by ________ / вҲҡ7.",
        "answer": "вҲҡ7"
      },
      {
        "prompt": "The product of (a + b) and (a - b) is ________. ",
        "answer": "aВІ - bВІ"
      }
    ],
    "mcqQuestions": [
      {
        "question": "What is the rationalized form of 3/вҲҡ2?",
        "options": [
          "A. \\frac{3}{\\sqrt{4}}",
          "B. \\frac{3\\sqrt{2}}{2}",
          "C. \\frac{6}{2}",
          "D. \\frac{3}{1}"
